/* ============================================================
   MOTION HELPERS
   ============================================================ */

function useReveal() {
  const ref = useRef(null);
  const [visible, setVisible] = useState(false);
  useEffect(() => {
    const el = ref.current;
    if (!el) return;
    const io = new IntersectionObserver(
      ([entry]) => {
        if (entry.isIntersecting) {
          setVisible(true);
          io.disconnect();
        }
      },
      { threshold: 0.12 }
    );
    io.observe(el);
    return () => io.disconnect();
  }, []);
  return [ref, visible];
}

function Reveal({ children, className = "", style = {} }) {
  const [ref, visible] = useReveal();
  return (
    <div ref={ref} className={`reveal ${visible ? "reveal-visible" : ""} ${className}`} style={style}>
      {children}
    </div>
  );
}

function useCountUp(target, active, duration = 1200) {
  const [value, setValue] = useState(0);
  const started = useRef(false);
  useEffect(() => {
    if (!active || started.current) return;
    started.current = true;
    const prefersReduced = window.matchMedia("(prefers-reduced-motion: reduce)").matches;
    if (prefersReduced) {
      setValue(target);
      return;
    }
    const start = performance.now();
    const ease = (t) => 1 - Math.pow(1 - t, 3);
    let raf;
    const tick = (now) => {
      const progress = Math.min(1, (now - start) / duration);
      setValue(Math.round(ease(progress) * target));
      if (progress < 1) raf = requestAnimationFrame(tick);
    };
    raf = requestAnimationFrame(tick);
    return () => cancelAnimationFrame(raf);
  }, [active, target, duration]);
  return value;
}

function CountUpStat({ target, active, suffix = "" }) {
  const value = useCountUp(target, active);
  return (
    <span style={{ fontFamily: "var(--display)", fontWeight: 600, fontSize: 30, fontVariantNumeric: "tabular-nums" }}>
      {value.toLocaleString()}{suffix}
    </span>
  );
}

function Gauge({ breakdown, solved, attempted, active }) {
  const radius = 80;
  const circumference = 2 * Math.PI * radius;
  const solvedCount = useCountUp(solved, active, 1400);

  let offsetAccum = 0;
  const segments = breakdown.map((b) => {
    const frac = b.solved / attempted;
    const length = frac * circumference;
    const seg = { ...b, length, offset: offsetAccum };
    offsetAccum += length;
    return seg;
  });

  return (
    <div style={{ position: "relative", width: 200, height: 200, margin: "0 auto" }}>
      <svg viewBox="0 0 200 200" width="200" height="200">
        <circle cx="100" cy="100" r={radius} fill="none" stroke="var(--line)" strokeWidth="10" />
        {segments.map((s, i) => (
          <circle
            key={s.label}
            cx="100"
            cy="100"
            r={radius}
            fill="none"
            stroke={s.color}
            strokeWidth="10"
            strokeLinecap="round"
            strokeDasharray={`${circumference}`}
            strokeDashoffset={active ? circumference - s.length : circumference}
            style={{
              transform: `rotate(${-90 + (s.offset / circumference) * 360}deg)`,
              transformOrigin: "100px 100px",
              transition: `stroke-dashoffset 1.2s cubic-bezier(0.16,1,0.3,1) ${i * 0.15}s`,
            }}
          />
        ))}
      </svg>
      <div style={{ position: "absolute", inset: 0, display: "flex", flexDirection: "column", alignItems: "center", justifyContent: "center" }}>
        <span style={{ fontFamily: "var(--display)", fontWeight: 700, fontSize: 34, fontVariantNumeric: "tabular-nums" }}>
          {solvedCount}
        </span>
        <span className="tag" style={{ color: "var(--ink-soft)" }}>/ {attempted.toLocaleString()}</span>
        <span className="eyebrow" style={{ marginTop: 4 }}>SOLVED</span>
      </div>
    </div>
  );
}

function Ruler() {
  return (
    <svg className="ruler" viewBox="0 0 1000 20" preserveAspectRatio="none" aria-hidden="true">
      {Array.from({ length: 51 }).map((_, i) => (
        <line key={i} x1={i * 20} x2={i * 20} y1={i % 5 === 0 ? 4 : 10} y2={16} stroke="var(--line)" strokeWidth="1" />
      ))}
    </svg>
  );
}

